export type { User } from '@supabase/supabase-js';

// --- CONFIGURATION ---
const SUPABASE_URL = 'https://rkalxppxkphbddmmozbl.supabase.co';
const SUPABASE_ANON_KEY = 'sb_publishable_GmjutU13Q02MxGsCWaB2lA_ymuPyX1I';

