// --- GUEST MODE HELPERS ---
const GUEST_ID_PREFIX = 'guest_';
const isGuest = (userId: string) => userId.startsWith(GUEST_ID_PREFIX);

export const signInAsGuest = () => {
  const guestId = GUEST_ID_PREFIX + Math.random().toString(36).substr(2, 9);
  const guestUser: any = {
    id: guestId,
    email: 'guest@healthyhub.elite',
    user_metadata: { full_name: 'Elite Guest' },
    is_guest: true
  };
