const mapProfileToAppFormat = (dbProfile: any): UserProfile => {
  const safeGoals = dbProfile.goals || {};
  const safeMetrics = dbProfile.metrics || {};
  return {
    id: dbProfile.id,
    name: dbProfile.name || 'Elite Member',
    email: dbProfile.email || '',
    avatarUrl: dbProfile.avatar_url || dbProfile.avatarUrl || DEFAULT_AVATAR,
    currentStreak: dbProfile.current_streak || 0,
    currentPlanName: dbProfile.current_plan_name,
    goals: {
        stepGoal: dbProfile.daily_step_goal || safeGoals.stepGoal || 10000,
        calorieGoal: dbProfile.daily_calorie_goal || safeGoals.calorieGoal || 2000,
        distanceGoal: Number(safeGoals.distanceGoal) || 5.0
    },
    metrics: {
        height: dbProfile.height || Number(safeMetrics.height) || 0,
        weight: dbProfile.weight || Number(safeMetrics.weight) || 0,
        age: Number(safeMetrics.age) || 25,
        gender: safeMetrics.gender || 'Other',
        dob: safeMetrics.dob || '',
        activityLevel: safeMetrics.activityLevel || 'Moderately Active',
        fitnessGoal: safeMetrics.fitnessGoal || 'Maintain',
        lastWeightUpdate: Number(safeMetrics.lastWeightUpdate) || Date.now(),
        lastHeightUpdate: Number(safeMetrics.lastHeightUpdate) || Date.now()
    }
  };
};

