export const updateProfile = async (user: User, profile: { displayName?: string, photoURL?: string }) => {
    if (isGuest(user.id)) {
        const stored = JSON.parse(localStorage.getItem(`profile_${user.id}`) || '{}');
        if (profile.displayName) stored.name = profile.displayName;
        if (profile.photoURL) stored.avatarUrl = profile.photoURL;
        localStorage.setItem(`profile_${user.id}`, JSON.stringify(stored));
        return;
    }

    const authUpdates: any = {};
    if (profile.displayName) authUpdates.data = { ...authUpdates.data, full_name: profile.displayName };
    if (profile.photoURL) authUpdates.data = { ...authUpdates.data, avatar_url: profile.photoURL };
    if (Object.keys(authUpdates).length > 0) await supabase.auth.updateUser(authUpdates);

    const dbUpdates: any = {};
    if (profile.displayName) dbUpdates.name = profile.displayName;
    if (profile.photoURL) dbUpdates.avatar_url = profile.photoURL;
    if (Object.keys(dbUpdates).length > 0) {
        await supabase.from('profiles').update(dbUpdates).eq('id', user.id);
    }
};

export const updateUserMetrics = async (uid: string, metrics: UserMetrics) => {
  if (isGuest(uid)) {
    const stored = JSON.parse(localStorage.getItem(`profile_${uid}`) || '{}');
    stored.metrics = metrics;
    localStorage.setItem(`profile_${uid}`, JSON.stringify(stored));
    return;
  }
  await supabase.from('profiles').update({ 
      metrics,
      weight: metrics.weight,
      height: metrics.height,
      bmi: metrics.weight / ((metrics.height/100) ** 2)
  }).eq('id', uid);
};

export const updateUserTargets = async (userId: string, targets: { calories?: number, steps?: number, plan_name?: string }) => {
  if (isGuest(userId)) return;
  const updates: any = {};
  if (targets.calories !== undefined) updates.daily_calorie_goal = targets.calories;
  if (targets.steps !== undefined) updates.daily_step_goal = targets.steps;
  if (targets.plan_name !== undefined) updates.current_plan_name = targets.plan_name;

  const { data: profile } = await supabase.from('profiles').select('goals').eq('id', userId).maybeSingle();
  const currentGoals = profile?.goals || {};

  updates.goals = {
    ...currentGoals,
    stepGoal: targets.steps ?? currentGoals.stepGoal,
    calorieGoal: targets.calories ?? currentGoals.calorieGoal
  };

  await supabase.from('profiles').update(updates).eq('id', userId);
};

