          duration: 0.3,
          easeLinearity: 1.0
        });
        hasInitialFocus.current = true;
      } else {
        map.panTo(center, { animate: true, duration: 0.5 });
      }
    }
  }, [center, isStarted, map]);
  return null;
};

const MapTrackingScreen: React.FC<MapTrackingScreenProps> = ({ userHeight = 175 }) => {
  const [isStarted, setIsStarted] = useState(false);
  const isStartedRef = useRef(false);

  const [position, setPosition] = useState<[number, number] | null>(null);
  const [path, setPath] = useState<[number, number][]>([]);
  const [distance, setDistance] = useState(0); 
  const [elapsedTime, setElapsedTime] = useState(0);

  const [isSyncing, setIsSyncing] = useState(false);
  const [isDataLoaded, setIsDataLoaded] = useState(false); // SAFETY GATE
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [userId, setUserId] = useState<string | null>(null);

  const watchId = useRef<number | null>(null);
  const timerId = useRef<number | null>(null);
  const syncTimerId = useRef<number | null>(null);

  // --- INITIALIZATION ---
  useEffect(() => {
    const init = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        setUserId(user.id);
        await _loadTodayData(user.id); // Fetch cloud data first
      }
    };
    init();

    if ("geolocation" in navigator) {
      watchId.current = navigator.geolocation.watchPosition(
        (pos) => {
          const { latitude, longitude } = pos.coords;
          const newPos: [number, number] = [latitude, longitude];
          setPosition(newPos);

          if (isStartedRef.current) {
            setPath(prev => {
              if (prev.length > 0) {
                const last = prev[prev.length - 1];
                const dist = L.latLng(last[0], last[1]).distanceTo(L.latLng(newPos[0], newPos[1]));
                if (dist > 1.5) { 
                  setDistance(d => d + dist);
                  return [...prev, newPos];
                }
                return prev;
              }
              return [newPos]; 
            });
          }
        },
        (err) => console.error("GPS Error:", err),
        { enableHighAccuracy: true, maximumAge: 0, timeout: 5000 }
      );
    }

    return () => {
      if (watchId.current !== null) navigator.geolocation.clearWatch(watchId.current);
      if (syncTimerId.current) clearInterval(syncTimerId.current);
    };
  }, []);

  // --- CROSS-DEVICE SYNC: LOAD DATA ---
  const _loadTodayData = async (uid: string) => {
    try {
      const today = new Date().toISOString().split('T')[0];
      const { data, error } = await supabase
        .from('daily_activity')
        .select('*')
        .eq('user_id', uid)
        .eq('activity_date', today)
        .maybeSingle();

      if (error) throw error;

      if (data) {
        // Restore progress from cloud: KM to Meters
        setDistance(data.distance_km * 1000);
        console.log("Restored today's cloud progress:", data.steps, "steps.");
      }
    } catch (e) {
      console.error("Cloud restoration failed:", e);
    } finally {
      setIsDataLoaded(true); // Release sync safety gate
    }
  };

  // --- STOPWATCH ---
  useEffect(() => {
    if (isStarted) {
      timerId.current = window.setInterval(() => setElapsedTime(t => t + 1), 1000);
    } else {
      if (timerId.current) clearInterval(timerId.current);
    }
    return () => { if (timerId.current) clearInterval(timerId.current); };
  }, [isStarted]);

  // --- AUTO-SAVE HEARTBEAT ---
  useEffect(() => {
    if (isStarted && userId && isDataLoaded) {
      syncTimerId.current = window.setInterval(() => _syncToCloud(), 30000);
    } else {
      if (syncTimerId.current) {
        clearInterval(syncTimerId.current);
        syncTimerId.current = null;
      }
    }
    return () => { if (syncTimerId.current) clearInterval(syncTimerId.current); };
  }, [isStarted, userId, isDataLoaded]);

  // --- SYNC FUNCTION ---
  const _syncToCloud = async () => {
    if (!userId || !isDataLoaded) return; // Never sync if data hasn't been fetched yet

    setIsSyncing(true);
    try {
      const strideLengthCm = userHeight * 0.415;
      const currentSteps = strideLengthCm > 0 ? Math.floor((distance * 100) / strideLengthCm) : 0;
      const caloriesBurned = Math.floor(currentSteps * 0.04);
      const distKm = parseFloat((distance / 1000).toFixed(2));

      const { data: profile } = await supabase.from('profiles').select('goals').eq('id', userId).maybeSingle();
      const stepGoal = profile?.goals?.stepGoal || 10000;

      await syncDailyActivity(userId, currentSteps, caloriesBurned, stepGoal, distKm);
      setLastSyncTime(new Date());
    } catch (e) {
      console.error("Cloud Sync Failure:", e);
    } finally {
      setTimeout(() => setIsSyncing(false), 2000);
    }
  };

  const startTracking = () => {
    // Note: We don't reset distance to 0 because we want to track the whole day's progress
    isStartedRef.current = true;
    setIsStarted(true);
    if (position) setPath([position]);
  };

  const stopTracking = async () => {
    isStartedRef.current = false;
    setIsStarted(false);
    await _syncToCloud(); // Save immediately on stop
  };

  const strideLengthCm = userHeight * 0.415;
  const steps = strideLengthCm > 0 ? Math.floor((distance * 100) / strideLengthCm) : 0;

  const formatTime = (s: number) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sec = s % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
  };

  return (
    <div className="relative h-full w-full bg-black overflow-hidden">
      <div className="absolute inset-0 z-0">
        <MapContainer 
          center={CHENNAI_COORDS} 
          zoom={12} 
          className="h-full w-full bg-[#111]"
          zoomControl={false}
          attributionControl={false}
        >
          <TileLayer 
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" 
            className="map-tiles-dark"
          />
          <MapController center={position} isStarted={isStarted} />
          {path.length > 1 && (
            <Polyline 
              positions={path} 
              pathOptions={{ color: '#CEF245', weight: 6, opacity: 1.0, lineCap: 'round', lineJoin: 'round' }} 
            />
          )}
          {position && <Marker position={position} icon={locationIcon} />}
        </MapContainer>

        {!position && (
           <div className="absolute inset-0 bg-black/60 flex items-center justify-center z-[10] backdrop-blur-sm">
              <div className="flex flex-col items-center animate-pulse text-luxury-neon">
                 <Loader2 size={32} className="mb-2 animate-spin" />
                 <span className="text-[10px] font-black uppercase tracking-[0.3em]">Acquiring Satellites...</span>
              </div>
           </div>
        )}
      </div>

      <motion.div 
        initial={{ y: 100, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.4, ease: "easeOut" }}
        className="absolute bottom-0 left-0 right-0 z-30 bg-[#0A0A0A]/95 backdrop-blur-2xl border-t border-white/10 rounded-t-[2.5rem] px-6 pt-6 pb-4 shadow-[0_-10px_40px_rgba(0,0,0,0.8)]"
      >
        <div className="flex flex-col gap-6"> 
            <div className="flex items-center justify-between px-2">
                <div className="flex items-center gap-2">
                    <NavIcon size={14} className="text-luxury-neon" />
                    <span className="text-[10px] font-black uppercase tracking-[0.2em] text-white/80">
                      {isStarted ? "Live Tracking Active" : "Tracking Ready"}
                    </span>
                </div>

                <div className="flex items-center gap-2">
                   <AnimatePresence mode="wait">
                      {isSyncing ? (
                         <motion.div key="syncing" initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.8 }} className="flex items-center gap-1.5">
                            <Upload size={12} className="text-luxury-neon animate-bounce" />
                            <span className="text-[8px] font-black text-luxury-neon uppercase tracking-widest">Syncing</span>
                         </motion.div>
                      ) : (
                         <motion.div key="idle" initial={{ opacity: 0 }} animate={{ opacity: 0.4 }} className="flex items-center gap-1.5">
                            <Cloud size={12} className="text-white" />
                            <span className="text-[8px] font-black text-white uppercase tracking-widest">
                               {!isDataLoaded ? "Initializing..." : lastSyncTime ? `Synced ${lastSyncTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}` : "Cloud Ready"}
                            </span>
                         </motion.div>
                      )}
                   </AnimatePresence>
                </div>
            </div>

            <div className="flex justify-between items-center px-2">
                <div className="flex flex-col items-center gap-1">
                    <div className="flex items-center gap-1 text-gray-500 mb-1">
                        <Timer size={14} />
                    </div>
                    <span className="text-2xl font-black text-white tabular-nums tracking-tight">{formatTime(elapsedTime)}</span>
                    <span className="text-[9px] font-black text-gray-600 uppercase tracking-widest">Duration</span>
                </div>

                <div className="w-px h-10 bg-white/5"></div>

                <div className="flex flex-col items-center gap-1">
                    <div className="flex items-center gap-1 text-gray-500 mb-1">
                        <MapIcon size={14} />
                    </div>
                    <span className="text-2xl font-black text-white tabular-nums tracking-tight">{(distance / 1000).toFixed(2)}</span>
                    <span className="text-[9px] font-black text-gray-600 uppercase tracking-widest">KM Dist</span>
                </div>

                <div className="w-px h-10 bg-white/5"></div>

                <div className="flex flex-col items-center gap-1">
                    <div className="flex items-center gap-1 text-gray-500 mb-1">
                        <Footprints size={14} />
                    </div>
                    <span className="text-2xl font-black text-white tabular-nums tracking-tight">{steps}</span>
                    <span className="text-[9px] font-black text-gray-600 uppercase tracking-widest">Steps</span>
                </div>
            </div>

            <div className="flex justify-center pb-2">
                {!isStarted ? (
                <button 
                    onClick={startTracking}
                    disabled={!position || !isDataLoaded}
                    className="px-12 py-4 bg-luxury-neon text-black font-black uppercase text-xs tracking-[0.25em] rounded-full flex items-center justify-center gap-3 shadow-[0_0_30px_rgba(206,242,69,0.25)] hover:scale-[1.05] active:scale-[0.98] transition-all disabled:opacity-30"
                >
                    <Play size={16} fill="black" /> Start Session
                </button>
                ) : (
                <button 
                    onClick={stopTracking}
                    className="px-12 py-4 bg-red-600 text-white font-black uppercase text-xs tracking-[0.25em] rounded-full flex items-center justify-center gap-3 shadow-[0_0_30px_rgba(220,38,38,0.4)] animate-pulse"
                >
                    <Square size={16} fill="white" /> Stop Session
                </button>
                )}
            </div>
        </div>
      </motion.div>
    </div>
  );
};

