export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) {
    const localData = JSON.parse(localStorage.getItem(`activity_${userId}_today`) || '{}');
    localData.steps = steps;
    localData.calories_burned = calories;
    localData.distance_km = distanceKm;
    localData.is_target_met = steps >= stepGoal;
    localData.updated_at = new Date().toISOString();
    localStorage.setItem(`activity_${userId}_today`, JSON.stringify(localData));
    return;
  }

  const today = new Date().toISOString().split('T')[0];
  const isTargetMet = steps >= stepGoal;

  try {
    // Strictly following the requested schema and upsert strategy
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: today, 
      steps: steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: isTargetMet,
      updated_at: new Date().toISOString()
    }, { 
      onConflict: 'user_id, activity_date' 
    });

    if (error) throw error;
  } catch (e) {
    console.error("Cloud Sync Error:", e);
    throw e;
  }
};

export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) {
    const storedProfile = localStorage.getItem(`profile_${userId}`);
    if (!storedProfile) return null;
    return {
      profile: JSON.parse(storedProfile),
      todayActivity: JSON.parse(localStorage.getItem(`activity_${userId}_today`) || 'null'),
      foodLogs: [],
      chatHistory: []
    };
  }
  try {
    const today = new Date().toISOString().split('T')[0];
    const { data: profileData, error: profileError } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
    if (profileError || !profileData) return null; 

    const [activityRes, foodRes, chatRes] = await Promise.all([
      supabase.from('daily_activity').select('*').eq('user_id', userId).eq('activity_date', today).maybeSingle(),
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(20),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(50)
    ]);

    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: activityRes.data as any | null,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    return null;
  }
};

export const checkAndUpdateStreak = async (userId: string, currentStepGoal: number) => {
  if (isGuest(userId)) return 1;
  const today = new Date().toISOString().split('T')[0];
  const yesterday = new Date(Date.now() - 86400000).toISOString().split('T')[0];

  try {
    const { data: profile } = await supabase.from('profiles').select('current_streak').eq('id', userId).maybeSingle();
    let streak = profile?.current_streak || 0;

    const { data: yesterdayActivity } = await supabase.from('daily_activity').select('is_target_met').eq('user_id', userId).eq('activity_date', yesterday).maybeSingle();
    if (!yesterdayActivity || !yesterdayActivity.is_target_met) {
       if (streak > 0) {
          streak = 0;
          await supabase.from('profiles').update({ current_streak: 0 }).eq('id', userId);
       }
    }
    return streak;
  } catch (e) {
    return 0;
  }
};

