import React, { useState, useEffect } from 'react';
import { AnimatePresence } from 'framer-motion';
import { 
  onAuthStateChanged,
  User,
  fetchFullUserDashboard,
  syncDailyActivity
} from './services/supabase';

import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import MapTrackingScreen from './components/MapTrackingScreen';
import ChatBot from './components/ChatBot';
import ProfileScreen from './components/ProfileScreen';
import OnboardingScreen from './components/OnboardingScreen'; 
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true); 
  const [isProfileChecking, setIsProfileChecking] = useState(false);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { isTracking, toggleTracking, liveSteps, resetLiveSteps } = usePedometer();

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0, calories: 0, distance: 0, stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0, history: []
  });

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(async (user) => {
      if (user) {
        setCurrentUser(user);
        setIsProfileChecking(true);

        const dashboardData = await fetchFullUserDashboard(user.id);

        if (dashboardData && dashboardData.profile) {
            setUserProfile(dashboardData.profile);
            setActivityData(prev => ({
              ...prev,
              steps: dashboardData.todayActivity?.steps || 0,
              calories: dashboardData.todayActivity?.calories_burned || 0,
              stepGoal: dashboardData.profile.goals?.stepGoal || prev.stepGoal,
              calorieGoal: dashboardData.profile.goals?.calorieGoal || prev.calorieGoal
            }));
        }
        setIsProfileChecking(false);
      } else { 
        setCurrentUser(null); 
        setUserProfile(null); 
      }
      setIsAuthChecking(false);
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  useEffect(() => {
    if (!currentUser) return;

    if (liveSteps > 0) {
       setActivityData(prev => {
          const newSteps = prev.steps + liveSteps;
          const newCals = prev.calories + (liveSteps * 0.04);
          syncDailyActivity(currentUser.id, newSteps, Math.floor(newCals), prev.stepGoal);
          return { ...prev, steps: newSteps, calories: newCals };
       });
       resetLiveSteps();
    }
  }, [liveSteps, currentUser, resetLiveSteps]);

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => setActivityData(prev => ({ ...prev, ...newGoals }));

  if (isAuthChecking) return <div className="h-screen bg-black flex items-center justify-center text-luxury-neon animate-pulse text-[10px] uppercase tracking-[0.3em]">Initialising Ecosystem...</div>;
  if (!currentUser) return <Auth onLoginSuccess={() => {}} />;
  if (isProfileChecking) return <div className="h-screen bg-black flex items-center justify-center text-gray-400 text-[10px] uppercase tracking-[0.3em]">Synchronizing Records...</div>;

  if (!userProfile) {
     return <OnboardingScreen user={currentUser} onComplete={(p) => { setUserProfile(p); setCurrentView(ViewState.DASHBOARD); }} />;
  }

  return (
    <div className="flex flex-col h-[100dvh] bg-black text-white relative overflow-hidden font-sans">
      <main className="flex-1 relative w-full overflow-hidden">
        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && <Dashboard key="dash" data={activityData} onUpdateGoals={handleUpdateGoals} isTracking={isTracking} onToggleTracking={toggleTracking} foodHistory={foodHistory} />}
          {currentView === ViewState.CHAT && <ChatBot key="chat" metrics={bmiMetrics} activity={activityData} />}
          {currentView === ViewState.FOOD_LENS && <FoodLens key="lens" history={foodHistory} onAddToHistory={h => setFoodHistory([h, ...foodHistory])} />}
          {currentView === ViewState.BMI_HUB && <BMIHub key="bmi" />}
          {currentView === ViewState.MAP_TRACKER && <MapTrackingScreen key="map" userHeight={bmiMetrics.height} />}
          {currentView === ViewState.PROFILE && <ProfileScreen key="profile" onUpdateMetrics={setBmiMetrics} />}
        </AnimatePresence>
      </main>
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { MapContainer, TileLayer, Polyline, Marker, useMap } from 'react-leaflet';
import L from 'leaflet';
import { motion } from 'framer-motion';
import { Play, Square, Navigation as NavIcon, Timer, Footprints, Map as MapIcon, Loader2 } from 'lucide-react';
import { supabase, syncDailyActivity } from '../services/supabase';

interface MapTrackingScreenProps {
  userHeight?: number;
}

const CHENNAI_COORDS: [number, number] = [13.0827, 80.2707];

const locationIcon = L.divIcon({
  className: 'custom-location-icon',
  html: `<div class="w-5 h-5 bg-blue-500 rounded-full border-4 border-white shadow-[0_0_20px_rgba(59,130,246,0.8)] animate-pulse"></div>`,
  iconSize: [20, 20],
  iconAnchor: [10, 10]
});

const MapController = ({ center }: { center: [number, number] | null }) => {
  const map = useMap();
  useEffect(() => {
    if (center) {
      map.flyTo(center, 18, { animate: true });
    }
  }, [center, map]);
  return null;
};

const MapTrackingScreen: React.FC<MapTrackingScreenProps> = ({ userHeight = 175 }) => {
  const [isStarted, setIsStarted] = useState(false);
  const [position, setPosition] = useState<[number, number] | null>(null);
  const [path, setPath] = useState<[number, number][]>([]);
  const [distance, setDistance] = useState(0); 
  const [elapsedTime, setElapsedTime] = useState(0);
  const [userId, setUserId] = useState<string | null>(null);

  const watchId = useRef<number | null>(null);
  const timerId = useRef<number | null>(null);

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => {
      if (data.user) setUserId(data.user.id);
    });

    if ("geolocation" in navigator) {
      watchId.current = navigator.geolocation.watchPosition(
        (pos) => {
          const newPos: [number, number] = [pos.coords.latitude, pos.coords.longitude];
          setPosition(newPos);

          if (isStarted) {
            setPath(prev => {
              if (prev.length > 0) {
                const last = prev[prev.length - 1];
                const d = L.latLng(last[0], last[1]).distanceTo(L.latLng(newPos[0], newPos[1]));
                if (d > 2) { 
                  setDistance(prevD => prevD + d);
                  return [...prev, newPos];
                }
              }
              return prev.length === 0 ? [newPos] : prev;
            });
          }
        },
        null,
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchId.current) navigator.geolocation.clearWatch(watchId.current); };
  }, [isStarted]);

  useEffect(() => {
    if (isStarted) {
      timerId.current = window.setInterval(() => setElapsedTime(t => t + 1), 1000);
    } else if (timerId.current) {
      clearInterval(timerId.current);
    }
    return () => { if (timerId.current) clearInterval(timerId.current); };
  }, [isStarted]);

  const toggleTracking = () => {
    if (!isStarted) {
      setDistance(0);
      setElapsedTime(0);
      setPath(position ? [position] : []);
    } else {
      _finalizeSync();
    }
    setIsStarted(!isStarted);
  };

  const _finalizeSync = async () => {
    if (!userId) return;
    const strideLengthCm = userHeight * 0.415;
    const steps = Math.floor((distance * 100) / strideLengthCm);
    const calories = Math.floor(steps * 0.04);
    syncDailyActivity(userId, steps, calories, 10000, parseFloat((distance/1000).toFixed(2)));
  };

  const formatTime = (s: number) => {
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return `${m.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
  };

  return (
    <div className="relative h-full w-full bg-black overflow-hidden">
      <div className="absolute inset-0 z-0">
        <MapContainer center={CHENNAI_COORDS} zoom={13} className="h-full w-full" zoomControl={false}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" className="map-tiles-dark" />
          <MapController center={position} />
          {path.length > 1 && <Polyline positions={path} pathOptions={{ color: '#CEF245', weight: 5 }} />}
          {position && <Marker position={position} icon={locationIcon} />}
        </MapContainer>
        {!position && (
           <div className="absolute inset-0 bg-black/40 backdrop-blur-sm flex flex-col items-center justify-center z-10">
              <Loader2 className="animate-spin text-luxury-neon mb-4" />
              <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white">Acquiring Location...</p>
           </div>
        )}
      </div>

      <motion.div 
        initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }}
        className="absolute bottom-6 left-6 right-6 z-20 glass-panel rounded-[2rem] p-6 shadow-2xl border border-white/10"
      >
        <div className="flex flex-col gap-6">
          <div className="flex justify-between items-center px-2">
            <div className="flex flex-col items-center gap-1">
              <Timer size={14} className="text-gray-500 mb-1" />
              <span className="text-xl font-black text-white tabular-nums">{formatTime(elapsedTime)}</span>
              <span className="text-[8px] font-black text-gray-600 uppercase tracking-widest">Time</span>
            </div>
            <div className="w-px h-8 bg-white/10"></div>
            <div className="flex flex-col items-center gap-1">
              <MapIcon size={14} className="text-gray-500 mb-1" />
              <span className="text-xl font-black text-white tabular-nums">{(distance/1000).toFixed(2)}</span>
              <span className="text-[8px] font-black text-gray-600 uppercase tracking-widest">KM</span>
            </div>
            <div className="w-px h-8 bg-white/10"></div>
            <div className="flex flex-col items-center gap-1">
              <Footprints size={14} className="text-gray-500 mb-1" />
              <span className="text-xl font-black text-white tabular-nums">{Math.floor((distance*100)/(userHeight*0.415))}</span>
              <span className="text-[8px] font-black text-gray-600 uppercase tracking-widest">Steps</span>
            </div>
          </div>

          <button 
            onClick={toggleTracking}
            disabled={!position}
            className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-black uppercase text-[10px] tracking-[0.2em] transition-all disabled:opacity-30 ${isStarted ? 'bg-red-500 text-white' : 'bg-luxury-neon text-black shadow-[0_0_20px_rgba(206,242,69,0.3)]'}`}
          >
            {isStarted ? <><Square size={14} fill="currentColor" /> Stop Track</> : <><Play size={14} fill="currentColor" /> Start Track</>}
          </button>
        </div>
      </motion.div>
    </div>
  );
};

export default MapTrackingScreen;

