import React, { useState, useEffect } from 'react';
import { AnimatePresence } from 'framer-motion';
import { 
  onAuthStateChanged,
  User,
  fetchFullUserDashboard,
  syncDailyActivity
} from './services/supabase';

import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import MapTrackingScreen from './components/MapTrackingScreen';
import ChatBot from './components/ChatBot';
import ProfileScreen from './components/ProfileScreen';
import OnboardingScreen from './components/OnboardingScreen'; 
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true); 
  const [isProfileChecking, setIsProfileChecking] = useState(false);

  // --- THE LOADING LOCK (Safety Gate) ---
  const [isInitialLoadComplete, setIsInitialLoadComplete] = useState(false);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { isTracking, toggleTracking, liveSteps, resetLiveSteps } = usePedometer();

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0, calories: 0, distance: 0, stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0, history: []
  });

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(async (user) => {
      setIsInitialLoadComplete(false); // Reset lock on auth change

      if (user) {
        setCurrentUser(user);
        setIsProfileChecking(true);

        try {
          // RULE: OnInit logic calls fetch before releasing the lock
          const dashboardData = await fetchFullUserDashboard(user.id);

          if (dashboardData && dashboardData.profile) {
              setUserProfile(dashboardData.profile);

              // RULE: Update steps to the database value (e.g., 50)
              setActivityData(prev => ({
                ...prev,
                steps: dashboardData.todayActivity?.steps || 0,
                calories: dashboardData.todayActivity?.calories_burned || 0,
                stepGoal: dashboardData.profile.goals?.stepGoal || prev.stepGoal,
                calorieGoal: dashboardData.profile.goals?.calorieGoal || prev.calorieGoal
              }));
          }
        } finally {
          // RULE: Only after the fetch finishes, set isLoading = false
          setIsInitialLoadComplete(true);
          setIsProfileChecking(false);
        }
      } else { 
        setCurrentUser(null); 
        setUserProfile(null);
        setIsInitialLoadComplete(false);
      }
      setIsAuthChecking(false);
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  useEffect(() => {
    // CRITICAL: Block sync if initial load is still pending
    if (!currentUser || !isInitialLoadComplete) {
      if (!isInitialLoadComplete && liveSteps > 0) {
        console.warn('⚠️ Blocked Save: Still Loading Dashboard Data');
      }
      return;
    }

    if (liveSteps > 0) {
       setActivityData(prev => {
          const newSteps = prev.steps + liveSteps;
          const newCals = prev.calories + (liveSteps * 0.04);

          // RULE: Sync to cloud only after the loading gate is open
          syncDailyActivity(currentUser.id, newSteps, Math.floor(newCals), prev.stepGoal);

          return { ...prev, steps: newSteps, calories: newCals };
       });
       resetLiveSteps();
    }
  }, [liveSteps, currentUser, isInitialLoadComplete, resetLiveSteps]);

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => setActivityData(prev => ({ ...prev, ...newGoals }));

  if (isAuthChecking) return <div className="h-screen bg-black flex items-center justify-center text-luxury-neon animate-pulse text-[10px] uppercase tracking-[0.3em]">Initialising Ecosystem...</div>;
  if (!currentUser) return <Auth onLoginSuccess={() => {}} />;
  if (isProfileChecking) return <div className="h-screen bg-black flex items-center justify-center text-gray-400 text-[10px] uppercase tracking-[0.3em]">Synchronizing Records...</div>;

  if (!userProfile) {
     return <OnboardingScreen user={currentUser} onComplete={(p) => { setUserProfile(p); setCurrentView(ViewState.DASHBOARD); }} />;
  }

  return (
    <div className="flex flex-col h-[100dvh] bg-black text-white relative overflow-hidden font-sans">
      <main className="flex-1 relative w-full overflow-hidden">
        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && <Dashboard key="dash" data={activityData} onUpdateGoals={handleUpdateGoals} isTracking={isTracking} onToggleTracking={toggleTracking} foodHistory={foodHistory} />}
          {currentView === ViewState.CHAT && <ChatBot key="chat" metrics={bmiMetrics} activity={activityData} />}
          {currentView === ViewState.FOOD_LENS && <FoodLens key="lens" history={foodHistory} onAddToHistory={h => setFoodHistory([h, ...foodHistory])} />}
          {currentView === ViewState.BMI_HUB && <BMIHub key="bmi" />}
          {currentView === ViewState.MAP_TRACKER && <MapTrackingScreen key="map" userHeight={bmiMetrics.height} />}
          {currentView === ViewState.PROFILE && <ProfileScreen key="profile" onUpdateMetrics={setBmiMetrics} />}
        </AnimatePresence>
      </main>
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  createUserDocument, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail,
  signInAsGuest,
  User
} from '../services/supabase'; 
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, CheckCircle, Camera, RefreshCw, ChevronRight, UserCircle2, Check, ArrowRight } from 'lucide-react';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  // Remember Me State
  const [rememberMe, setRememberMe] = useState(false);

  // Avatar Capture State
  const [showCamera, setShowCamera] = useState(false);
  const [tempUser, setTempUser] = useState<User | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetError, setResetError] = useState<string | null>(null);
  const [resetSuccess, setResetSuccess] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // --- INIT: CHECK LOCAL STORAGE ---
  useEffect(() => {
    const savedEmail = localStorage.getItem('healthy_hub_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  // --- CAMERA FUNCTIONS ---
  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: { ideal: 500 }, height: { ideal: 500 } }
      });
      setStream(mediaStream);
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play().catch(e => console.error("Video play failed", e));
        }
      }, 100);
    } catch (err) {
      setError("Could not access camera for profile photo.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        ctx.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(base64);
        stopCamera();
      }
    }
  };

