    // Use local scope to strictly clear local session data and avoid external redirects
    await supabase.auth.signOut({ scope: 'local' });
  } catch (err) {
    console.error("Supabase signOut error:", err);
    // Even if the network fails, we ensure local guest data is wiped
    localStorage.removeItem(GUEST_KEY);
  }
};

export const createUserWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signUp({ email, password: psw });
  if (error) throw error;
  localStorage.removeItem(GUEST_KEY);
  return { data };
};

export const createUserDocument = async (user: User, name: string) => {
  if (isGuest(user.id)) return;
  await supabase.from('profiles').upsert({ id: user.id, email: user.email, name, avatar_url: DEFAULT_AVATAR });
};

export const updateUserMetrics = (uid: string, metrics: UserMetrics) => {
  if (isGuest(uid)) return Promise.resolve(null);
  return supabase.from('profiles').update({ metrics, weight: metrics.weight, height: metrics.height }).eq('id', uid);
};

export const updateUserTargets = (userId: string, targets: any) => {
  if (isGuest(userId)) return Promise.resolve(null);
  return supabase.from('profiles').update({ daily_calorie_goal: targets.calories, daily_step_goal: targets.steps, goals: targets }).eq('id', userId);
};

// IMPROVED: Now robustly persists all onboarding data to profiles table
export const completeOnboarding = async (user: User, profileData: UserProfile, activityGoals: ActivityData) => {
  if (isGuest(user.id)) {
     return profileData;
  }

  const data = { 
    id: user.id, 
    email: user.email, 
    name: profileData.name, 
    avatar_url: profileData.avatarUrl, 
    daily_step_goal: activityGoals.stepGoal, 
    daily_calorie_goal: activityGoals.calorieGoal,
    weight: profileData.metrics?.weight,
    height: profileData.metrics?.height,
    metrics: profileData.metrics, // Contains dob, activityLevel, etc.
    goals: activityGoals,
    updated_at: new Date().toISOString()
  };

  const { error } = await supabase.from('profiles').upsert(data);
  if (error) throw error;

  return mapProfileToAppFormat(data);
};

export const fetchStreakCalendarData = async (userId: string) => {
  if (isGuest(userId)) return { streakDates: [] };
  const { data } = await supabase.from('daily_activity').select('activity_date').eq('user_id', userId).eq('is_target_met', true);
  return { streakDates: data?.map(d => d.activity_date) || [] };
};

export const checkAndUpdateStreak = async (userId: string) => {
  if (isGuest(userId)) return 0;
  const { data } = await supabase.from('profiles').select('current_streak').eq('id', userId).maybeSingle();
  return data?.current_streak || 0;
};

export const fetchChatHistory = async (userId: string) => {
  if (isGuest(userId)) return [];
  const { data } = await supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true });
  return data || [];
};

export const saveChatMessage = (userId: string, message: string, is_user_message: boolean, plan_data?: any) => {
  if (isGuest(userId)) return Promise.resolve(null);
  return supabase.from('chat_history').insert({ user_id: userId, message, is_user_message, plan_data });
};

export const updateProfile = (user: User, data: any) => {
  if (isGuest(user.id)) return Promise.resolve(null);
  return supabase.from('profiles').update({ name: data.displayName, avatar_url: data.photoURL }).eq('id', user.id);
};

export const sendPasswordResetEmail = (email: string) => supabase.auth.resetPasswordForEmail(email);

export const signInAsGuest = () => {
  localStorage.setItem(GUEST_KEY, 'true');
  // Trigger a page reload to ensure the guest state is picked up by onAuthStateChanged
  window.location.reload();
};

export const submitAiFeedback = async (image_url?: string, predicted_food?: string, user_feedback?: string) => {
  console.log("AI Feedback submitted:", { image_url, predicted_food, user_feedback });
  return true;
};

