import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  createUserDocument, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail,
  signInAsGuest,
  User
} from '../services/supabase'; 
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, CheckCircle, Camera, RefreshCw, ChevronRight, UserCircle2, Check, ArrowRight, Clock } from 'lucide-react';
import Logo from './Logo';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  // Cooldown State
  const [lockoutTimer, setLockoutTimer] = useState(0);

  // Remember Me State
  const [rememberMe, setRememberMe] = useState(false);

  // Avatar Capture State
  const [showCamera, setShowCamera] = useState(false);
  const [tempUser, setTempUser] = useState<User | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetError, setResetError] = useState<string | null>(null);
  const [resetSuccess, setResetSuccess] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // --- INIT: CHECK LOCAL STORAGE & COOLDOWN ---
  useEffect(() => {
    const savedEmail = localStorage.getItem('healthy_hub_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (lockoutTimer > 0) {
      interval = window.setInterval(() => {
        setLockoutTimer((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [lockoutTimer]);

  // --- CAMERA FUNCTIONS ---
  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: { ideal: 500 }, height: { ideal: 500 } }
      });
      setStream(mediaStream);
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play().catch(e => console.error("Video play failed", e));
        }
      }, 100);
    } catch (err) {
      setError("Could not access camera for profile photo.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        ctx.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(base64);
        stopCamera();
      }
    }
  };

  const handleRetake = () => {
    setCapturedImage(null);
    startCamera();
  };

  const handleSaveAvatar = async () => {
    if (!capturedImage || !tempUser) return;
    setIsLoading(true);
    try {
      await updateProfile(tempUser, { photoURL: capturedImage });
      onLoginSuccess();
    } catch (e) {
      setError("Failed to save profile photo.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSkipAvatar = () => {
    stopCamera();
    onLoginSuccess();
  };

  const handleGuestMode = () => {
    setIsLoading(true);
    signInAsGuest(); // This will reload and bypass auth
  };

  // --- AUTH LOGIC ---
  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (lockoutTimer > 0) return;

    setError(null);
    setSuccessMsg(null);
    setIsLoading(true);

    try {
      if (isLogin) {
        const data = await signInWithEmailAndPassword(email, password);
        console.log(`✅ LOGIN SUCCESS! User: ${data.user?.email}`);

        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }

        onLoginSuccess();
      } else {
        if (password !== confirmPassword) throw new Error("Passwords do not match.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");

        const { data } = await createUserWithEmailAndPassword(email, password);
        console.log(`✅ SIGNUP SUCCESS! User: ${data.user?.email}`);

        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }

        const user = data.user;
        if (user) {
            if (name) {
                await updateProfile(user, { displayName: name });
                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'Elite User');
            }
            setTempUser(user);
            setShowCamera(true);
            startCamera();
        }
      }
    } catch (err: any) {
      console.error('❌ AUTH ERROR:', err);

      let msg = err.message || "Authentication failed.";
      const lowerMsg = msg.toLowerCase();

      // Handle Rate Limits
      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests") || lowerMsg.includes("throttled")) {
        msg = "Too many attempts. To protect your account, authentication is temporarily throttled. Please wait 60 seconds.";
        setLockoutTimer(60);
      } else if (lowerMsg.includes("invalid login credentials") || lowerMsg.includes("user not found")) {
        msg = "We couldn't find a matching account. Please verify your password or use 'Sign Up' if you haven't created an account yet.";
      } else if (lowerMsg.includes("email already in use")) {
        msg = "This email is already registered. Try logging in instead.";
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetPassword = async () => {
    if (!resetEmail) return;
    setResetError(null);
    setResetSuccess(null);
    try {
        await sendPasswordResetEmail(resetEmail);
        setResetSuccess("Recovery link sent to " + resetEmail);
        console.log(`🔑 Reset Link Sent: ${resetEmail}`);
        setTimeout(() => setIsResetModalOpen(false), 3000);
    } catch(err: any) {
        console.error('❌ Reset Error:', err);
        setResetError(err.message || "Failed to send reset link.");
    }
  };

  return (
    <div className="min-h-screen w-full flex flex-col bg-black font-sans relative overflow-y-auto no-scrollbar">
      <div className="absolute inset-0 z-0 bg-cover bg-center grayscale blur-md opacity-40 scale-105"
        style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1534438327276-14e5300c3a48?q=80&w=2070&auto=format&fit=crop")' }} />
      <div className="absolute inset-0 z-0 bg-gradient-to-b from-black/80 via-black/90 to-black"></div>

      <AnimatePresence>
        {showCamera && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black flex flex-col items-center justify-center p-6"
          >
             <div className="w-full max-md flex flex-col items-center space-y-8">
                <div className="text-center">
                   <h2 className="text-2xl font-black text-white uppercase tracking-widest mb-2">Bio-Identity</h2>
                   <p className="text-gray-400 text-xs">Capture your profile avatar for the elite network.</p>
                </div>
                <div className="relative w-64 h-64 rounded-full overflow-hidden border-4 border-luxury-neon shadow-[0_0_40px_rgba(206,242,69,0.3)] bg-gray-900">
                    {capturedImage ? (
                        <img src={capturedImage} className="w-full h-full object-cover" alt="Captured" />
                    ) : (
                        <>
                           <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover mirror-mode" />
                           <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                              {!stream && <Loader2 className="animate-spin text-luxury-neon" />}
                           </div>
                        </>
                    )}
