                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'Elite User');
            }
            setTempUser(user);
            setShowCamera(true);
            startCamera();
        }
      }
    } catch (err: any) {
      console.error('❌ AUTH ERROR:', err);

      let msg = err.message || "Authentication failed.";
      const lowerMsg = msg.toLowerCase();

      // Handle Rate Limits
      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests") || lowerMsg.includes("throttled")) {
        msg = "Too many attempts. To protect your account, authentication is temporarily throttled. Please wait 60 seconds.";
        setLockoutTimer(60);
      } else if (lowerMsg.includes("invalid login credentials") || lowerMsg.includes("user not found")) {
        msg = "We couldn't find a matching account. Please verify your password or use 'Sign Up' if you haven't created an account yet.";
      } else if (lowerMsg.includes("email already in use")) {
        msg = "This email is already registered. Try logging in instead.";
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

