                disabled={isLoading || lockoutTimer > 0} 
                className="w-full py-4 bg-luxury-neon text-black font-black uppercase tracking-widest text-sm rounded-xl shadow-lg shadow-luxury-neon/20 disabled:opacity-50 mt-4 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2"
              >
                 {isLoading ? (
                    <Loader2 className="animate-spin" size={20} />
                 ) : lockoutTimer > 0 ? (
                    <>Throttled: Retry in {lockoutTimer}s</>
                 ) : (
                    isLogin ? "Authenticate" : "Create Account"
                 )}
              </button>
            </form>

            <div className="flex flex-col gap-4 mt-6">
               <button 
                  onClick={handleGuestMode}
                  disabled={isLoading || lockoutTimer > 0}
                  className="w-full py-3 bg-white/5 border border-white/10 text-gray-400 font-bold uppercase tracking-widest text-[10px] rounded-xl flex items-center justify-center gap-2 hover:bg-white/10 hover:text-white transition-all disabled:opacity-50"
               >
                  {isLoading ? <Loader2 size={16} className="animate-spin" /> : <><UserCircle2 size={16} /> Continue as Guest</>}
               </button>
            </div>

            <div className="mt-8 pt-6 border-t border-white/5 text-center">
              <button onClick={() => { setIsLogin(!isLogin); setError(null); }} className="text-sm font-bold text-gray-400 hover:text-white transition-colors">
                 {isLogin ? "New to the hub?" : "Already a member?"} <span className="text-luxury-neon ml-1">Swap Protocol</span>
              </button>
            </div>

            {/* Extra padding at bottom for scroll safety */}
            <div className="h-20 md:h-0" />
          </motion.div>
        </div>
      )}

      <AnimatePresence>
        {isResetModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-6">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setIsResetModalOpen(false)} className="absolute inset-0 bg-black/90 backdrop-blur-sm" />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-sm glass-panel p-8 rounded-3xl border border-white/10">
               <h2 className="text-xl font-black text-white uppercase tracking-widest mb-4">Reset Access</h2>
               <p className="text-xs text-gray-400 mb-6 leading-relaxed">Enter your registered email to receive recovery instructions.</p>

               {resetError && (
                  <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} className="bg-red-500/10 border border-red-500/20 rounded-xl p-3 mb-4 flex items-center gap-3 text-red-400 text-xs font-bold">
                    <AlertCircle size={14} className="shrink-0" /> <span className="flex-1">{resetError}</span>
                  </motion.div>
               )}
               {resetSuccess && (
                  <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} className="bg-green-500/10 border border-green-500/20 rounded-xl p-3 mb-4 flex items-center gap-3 text-green-400 text-xs font-bold">
                    <CheckCircle size={14} className="shrink-0" /> <span className="flex-1">{resetSuccess}</span>
                  </motion.div>
               )}

               <input 
                  type="email" 
                  value={resetEmail} 
                  onChange={(e) => setResetEmail(e.target.value)} 
                  placeholder="Email Address" 
                  className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none mb-4 focus:border-luxury-neon transition-all" 
               />
               <button onClick={handleResetPassword} className="w-full py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl hover:bg-gray-200 transition-colors">Send Recovery Link</button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

